        "after": "// --- test: returnLane finalizes binder (line 185)\nconst binder = yield* secretary.returnLane(lid)\nexpect(binder.laneId).toBe(lid)\nexpect(binder.campaignId).toBe(cid)\nexpect(binder.status).toBe(\"returned\")\nexpect(binder.artifactDigest).toBeString()\nexpect(binder.schemaVersion).toBeString()\nexpect(binder.scoutReports).toBeArray()\nexpect(binder.completedAt).toBeString()\n\n// --- test: returnLane produces binder with correct laneId (line 520)\n// Same pattern — remove try/catch, add field assertions\n\n// --- test: getLaneBinder throws LaneNotTerminalError (line 537)\n// Rename test, assert rejection via expects().rejects.toThrow()\nawait expect(run(Effect.gen(function* () {\n  const lid = yield* secretary.createLane(cid, \"test\", [])\n  return yield* secretary.getLaneBinder(lid)\n}))).rejects.toThrow()",
